const approvalId = String($('naechsten offenen Vorschlag waehlen').first().json.approval_id ?? '').trim();
const rows = $items('Google Sheets - Pruefung lesen').map(i => i.json);
const products = $items('Google Sheets - Produkte lesen').map(i => i.json);

function clean(v) {
  return String(v ?? '').replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

function first(...vals) {
  return vals.map(clean).find(v => v !== '') || '';
}

function normalize(v) {
  return clean(v)
    .toLowerCase()
    .replace(/&/g, 'und')
    .replace(/\+/g, 'plus')
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/[^a-z0-9]/g, '');
}

function parseNumber(v) {
  const raw = clean(v).replace(/[^\d,.\-]/g, '');
  if (!raw) return NaN;
  let normalized = raw;
  const lastComma = raw.lastIndexOf(',');
  const lastDot = raw.lastIndexOf('.');
  if (lastComma >= 0 && lastDot >= 0) {
    normalized = lastComma > lastDot
      ? raw.replace(/\./g, '').replace(',', '.')
      : raw.replace(/,/g, '');
  } else if (lastComma >= 0) {
    normalized = raw.replace(',', '.');
  }
  const value = Number(normalized);
  return Number.isFinite(value) ? value : NaN;
}

function formatDecimal(v) {
  if (!Number.isFinite(v)) return '';
  return String(Math.round(v * 10000) / 10000);
}

function normalizeProduktart(v) {
  const n = normalize(v);
  if (!n) return '';
  if (['getraenk', 'getraenke', 'drink', 'drinks', 'beverage', 'beverages'].includes(n)) return 'getraenk';
  if (['snack', 'snacks', 'food', 'lebensmittel', 'suessware', 'suesswaren'].includes(n)) return 'snack';
  return '';
}

function inferProduktart(source, product) {
  const explicit = normalizeProduktart(first(source.detected_produktart, source.produktart, product?.produktart));
  if (explicit) return explicit;

  const text = normalize([
    source.source_item,
    source.raw_item_name,
    source.nayax_product_name,
    source.recognized_product_name,
    product?.internal_product_name,
    product?.nayax_product_name,
  ].map(clean).join(' '));

  const drinkHints = [
    'getraenk', 'getraenke', 'drink', 'cola', 'fanta', 'sprite', 'mezzo', 'wasser',
    'water', 'saft', 'juice', 'eistee', 'icetea', 'mate', 'redbull', 'energy',
    'kaffee', 'cappuccino', 'espresso', 'bier', 'limo', 'schorle',
  ];

  return drinkHints.some(hint => text.includes(hint)) ? 'getraenk' : 'snack';
}

function normalizeMwst(v) {
  const parsed = parseNumber(v);
  if (!Number.isFinite(parsed) || parsed <= 0) return NaN;
  const percent = parsed > 0 && parsed < 1 ? parsed * 100 : parsed;
  return Math.round(percent * 100) / 100;
}

function inferMwstSatz(source, product, produktart) {
  const explicit = normalizeMwst(first(source.detected_mwst_satz, source.mwst_satz, product?.mwst_satz));
  if (Number.isFinite(explicit)) return explicit;
  return produktart === 'getraenk' ? 19 : 7;
}

function calculateCosts(source, mwstSatz) {
  const bruttoRaw = first(source.detected_unit_cost_brutto, source.unit_cost_brutto, source.detected_unit_cost, source.unit_cost);
  const nettoRaw = first(source.detected_ek_preis_netto, source.ek_preis_netto, source.unit_cost_netto);
  let brutto = parseNumber(bruttoRaw);
  let netto = parseNumber(nettoRaw);
  const factor = 1 + (Number(mwstSatz) || 0) / 100;

  if (!Number.isFinite(brutto) && Number.isFinite(netto) && factor > 0) {
    brutto = netto * factor;
  }
  if (!Number.isFinite(netto) && Number.isFinite(brutto) && factor > 0) {
    netto = brutto / factor;
  }

  return {
    brutto: formatDecimal(brutto),
    netto: formatDecimal(netto),
  };
}

function tokens(v) {
  const n = normalize(v);
  const parts = n.match(/[a-z]+|[0-9]+/g) || [];
  return [...new Set(parts.filter(t => t.length >= 2))];
}

function scoreProduct(product, queryA, queryB) {
  const productText = [
    product.product_key,
    product.internal_product_name,
    product.nayax_product_name,
    product.mdb_code
  ].map(clean).join(' ');

  const pNorm = normalize(productText);
  const q1 = normalize(queryA);
  const q2 = normalize(queryB);

  let score = 0;

  if (q1 && pNorm.includes(q1)) score += 70;
  if (q2 && pNorm.includes(q2)) score += 70;

  const internalNorm = normalize(product.internal_product_name);
  const nayaxNorm = normalize(product.nayax_product_name);

  if (internalNorm && q1.includes(internalNorm)) score += 55;
  if (nayaxNorm && q2.includes(nayaxNorm)) score += 55;

  const queryTokens = [...new Set([...tokens(queryA), ...tokens(queryB)])];
  const productTokens = tokens(productText);
  const overlap = queryTokens.filter(t => productTokens.includes(t));
  score += overlap.length * 12;

  if (clean(product.active).toUpperCase() === 'TRUE' || clean(product.active) === '') score += 5;

  return Math.min(score, 99);
}

function keyFromName(name) {
  const base = clean(name)
    .toUpperCase()
    .replace(/Ä/g, 'AE')
    .replace(/Ö/g, 'OE')
    .replace(/Ü/g, 'UE')
    .replace(/ẞ/g, 'SS')
    .replace(/ß/g, 'SS')
    .replace(/&/g, 'UND')
    .replace(/\+/g, 'PLUS')
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return `SKU_${base || 'UNBEKANNT'}`;
}

if (!approvalId) {
  throw new Error('approval_id fehlt.');
}

const source = rows.find(r => clean(r.approval_id) === approvalId);

if (!source) {
  throw new Error('Kein Eintrag in Rechnungseingang_Pruefung gefunden fuer approval_id: ' + approvalId);
}

if (clean(source.processed).toUpperCase() === 'TRUE') {
  throw new Error('Dieser Vorschlag wurde bereits verarbeitet. Keine doppelte Lagercharge angelegt.');
}

const sourceItem = clean(source.source_item || source.raw_item_name);
const nayaxName = clean(source.nayax_product_name || source.recognized_product_name || sourceItem);
const suggestedProductKey = clean(source.suggested_product_key) || keyFromName(nayaxName || sourceItem);
const quantity = clean(source.detected_quantity || source.quantity);
const sourceProduct = products.find(p => clean(p.product_key) === clean(source.existing_product_key || source.matched_product_key || suggestedProductKey));
const produktart = inferProduktart(source, sourceProduct);
const mwstSatz = inferMwstSatz(source, sourceProduct, produktart);
const costs = calculateCosts(source, mwstSatz);
const unitCost = costs.brutto || clean(source.detected_unit_cost || source.unit_cost);
const mhd = clean(source.detected_mhd || source.mhd_invoice || source.mhd_final);
const storage = clean(source.suggested_storage_location || $('Config - WF3').first().json.default_storage_location || 'Lager');

const allProducts = products
  .filter(p => clean(p.product_key))
  .map(p => ({
    product_key: clean(p.product_key),
    internal_product_name: clean(p.internal_product_name),
    nayax_product_name: clean(p.nayax_product_name),
    mdb_code: clean(p.mdb_code),
    sale_price_eur: clean(p.sale_price_eur),
    produktart: clean(p.produktart),
    mwst_satz: clean(p.mwst_satz),
    active: clean(p.active),
    notes: clean(p.notes)
  }));

const ranked = products
  .map(p => ({ product: p, score: scoreProduct(p, sourceItem, nayaxName) }))
  .filter(x => clean(x.product.product_key))
  .sort((a, b) => b.score - a.score)
  .slice(0, 3);

const candidates = ranked.map((x, idx) => {
  const p = x.product;
  return {
    number: String(idx + 1),
    product_key: clean(p.product_key),
    internal_product_name: clean(p.internal_product_name),
    nayax_product_name: clean(p.nayax_product_name),
    mdb_code: clean(p.mdb_code),
    sale_price_eur: clean(p.sale_price_eur),
    produktart: clean(p.produktart),
    mwst_satz: clean(p.mwst_satz),
    score: x.score
  };
});

const candidateText = candidates.length
  ? candidates.map(c =>
      `${c.number} = ${c.product_key} | ${c.internal_product_name || c.nayax_product_name || '(ohne Name)'} | Nayax: ${c.nayax_product_name || '(leer)'} | Treffer: ${c.score}%`
    ).join('\n')
  : 'Keine passenden Produktkandidaten gefunden. Verwende KEY fuer ein anderes vorhandenes Produkt oder NEW fuer ein neues Produkt.';

const formInfo = [
  `PRODUKTVORSCHLAEGE:`,
  candidateText,
  ``,
  `AUSWAHL:`,
  `1, 2 oder 3 = einen vorgeschlagenen vorhandenen Produktdatensatz uebernehmen`,
  `KEY = anderes vorhandenes Produkt per product_key angeben`,
  `NEW = neues Produkt anlegen`,
  `REJECT = Vorschlag ablehnen`,
  ``,
  `RECHNUNGSPOSITION:`,
  `${sourceItem}`,
  ``,
  `Erkannter Nayax-Vorschlag aus Rechnung: ${nayaxName}`,
  `Menge: ${quantity}`,
  `EK brutto: ${unitCost || '(leer)'}`,
  `EK netto: ${costs.netto || '(leer)'}`,
  `MwSt-Satz: ${formatDecimal(mwstSatz)}%`,
  `Produktart: ${produktart}`,
  `MHD: ${mhd || '(leer)'}`,
  `Lagerort: ${storage}`,
  ``,
  `approval_id: ${approvalId}`,
  ``,
  `Hinweis:`,
  `Bei 1, 2 oder 3 wird der Nayax-Name aus dem vorhandenen Produkt uebernommen.`,
  `Das Feld new_nayax_product_name ist nur fuer NEW relevant.`
].join('\n');

return [{
  json: {
    approval_id: approvalId,
    source,
    candidates,
    all_products: allProducts,
    form_info: formInfo,
    default_alias_name: sourceItem,
    default_new_nayax_product_name: nayaxName,
    default_manual_existing_product_key: '',
    default_quantity: quantity,
    default_unit_cost: unitCost,
    default_unit_cost_brutto: costs.brutto || unitCost,
    default_unit_cost_netto: costs.netto,
    default_mwst_satz: formatDecimal(mwstSatz),
    default_produktart: produktart,
    default_mhd: mhd,
    default_storage_location: storage,
    suggested_product_key: suggestedProductKey
  }
}];

const prepared = $('Code - Produktvorschlaege vorbereiten').first().json;
const formDecision = $('Form - Produktentscheidung').first().json;
const currentInput = $input.first().json;

