  const raw = clean(v).replace(/[^\d,.\-]/g, '');
  if (!raw) return NaN;
  let normalized = raw;
  const lastComma = raw.lastIndexOf(',');
  const lastDot = raw.lastIndexOf('.');
  if (lastComma >= 0 && lastDot >= 0) {
    normalized = lastComma > lastDot
      ? raw.replace(/\./g, '').replace(',', '.')
      : raw.replace(/,/g, '');
  } else if (lastComma >= 0) {
    normalized = raw.replace(',', '.');
  }
  const value = Number(normalized);
  return Number.isFinite(value) ? value : NaN;
}

function formatDecimal(v) {
  if (!Number.isFinite(v)) return '';
  return String(Math.round(v * 10000) / 10000);
}

function normalizeProduktart(v) {
  const n = normalize(v);
  if (!n) return '';
  if (['getraenk', 'getraenke', 'drink', 'drinks', 'beverage', 'beverages'].includes(n)) return 'getraenk';
  if (['snack', 'snacks', 'food', 'lebensmittel', 'suessware', 'suesswaren'].includes(n)) return 'snack';
  return '';
}

function inferProduktart(...vals) {
  const explicit = vals.map(normalizeProduktart).find(Boolean);
  if (explicit) return explicit;

  const text = normalize(vals.map(clean).join(' '));
  const drinkHints = [
    'getraenk', 'getraenke', 'drink', 'cola', 'fanta', 'sprite', 'mezzo', 'wasser',
    'water', 'saft', 'juice', 'eistee', 'icetea', 'mate', 'redbull', 'energy',
    'kaffee', 'cappuccino', 'espresso', 'bier', 'limo', 'schorle',
  ];

  return drinkHints.some(hint => text.includes(hint)) ? 'getraenk' : 'snack';
}

